// Detect factory layout by scanning the first ~10 rows for known anchor strings.
// Outputs: { factory: 'A'|'B'|'C'|'UNKNOWN', rawRows: [...], fileName: '...' }
const rows = $input.first().json && Array.isArray($input.first().json.data)
  ? $input.first().json.data
  : items.map(i => i.json);

const flat = JSON.stringify(rows.slice(0, 12)).toLowerCase();
let factory = 'UNKNOWN';
if (flat.includes('aurelia') || flat.includes('gold rate (usd/oz)')) factory = 'A';
else if (flat.includes('reference po:') || flat.includes('gold spot (usd/oz)')) factory = 'B';
else if (flat.includes('ring summary') || flat.includes('stone detail')) factory = 'C';

return [{ json: { factory, rawRows: rows, fileName: $('Watch invoices folder').item.json.path } }];

// Parse the LLM's JSON response and emit one item per invoice line plus
// a sibling item carrying the original file path (used for archiving).
const raw = $json.content?.[0]?.text || $json.text || $json.message?.content || '';
let parsed;
try {
  parsed = JSON.parse(raw.replace(/^```json\s*|```\s*$/g, '').trim());
} catch (err) {
  throw new Error('LLM did not return valid JSON: ' + err.message + '\n---\n' + raw.slice(0, 500));
}

const lines = Array.isArray(parsed.lines) ? parsed.lines : [];
const sourcePath = $('Detect factory layout').item.json.fileName;

return [
  { json: { canonical: { lines }, sourcePath, lineCount: lines.length } }
];

// Flatten the canonical structure into a single row per (uid, diamond)
// for the Excel writer. Ring rows have diamond fields blank; diamond rows
// reuse the parent UID so a human can read both pivots in one sheet.
const out = [];
for (const line of $json.canonical.lines) {
  out.push({
    uid: line.uid,
    po: line.po,
    po_sent_date: line.po_sent_date,
    sku: line.sku,
    quantity: line.quantity,
    karat: line.karat,
    color: line.color,
    gold_weight_g: line.gold_weight_g,
    gold_price_usd_per_oz: line.gold_price_usd_per_oz,
    labour_cost_usd: line.labour_cost_usd,
    final_cost_usd: line.final_cost_usd,
    diamond_shape: '',
    diamond_quality: '',
    diamond_carats: '',
    diamond_count: '',
    diamond_price_per_carat_usd: ''
  });
  for (const d of (line.diamonds || [])) {
    out.push({
      uid: line.uid,
      po: '', po_sent_date: '', sku: '', quantity: '', karat: '', color: '',
      gold_weight_g: '', gold_price_usd_per_oz: '',
      labour_cost_usd: '', final_cost_usd: '',
      diamond_shape: d.shape,
      diamond_quality: d.quality,
      diamond_carats: d.carats,
      diamond_count: d.count,
      diamond_price_per_carat_usd: d.price_per_carat_usd
    });
  }
}
return out.map(json => ({ json }));
